// ============================================================
// COMMON TYPES
// ============================================================

export type UUID = string;
export type Timestamp = Date;
export type TimestampWithTimezone = Date;
export type JsonB = Record<string, unknown>;
export type Bytea = Buffer;

// ============================================================
// ENUM TYPES (from CHECK constraints)
// ============================================================

export type SubscriptionStatus = 'demo' | 'trialing' | 'active' | 'past_due' | 'cancelled' | 'unpaid';
export type UserRole = 'user' | 'admin' | 'super_admin';
export type OAuthProvider = 'google' | 'facebook' | 'github';
export type ProductUnit = 'sqft' | 'sqm' | 'linear_ft' | 'linear_m' | 'each';
export type QuoteItemUnit = 'in' | 'ft' | 'cm' | 'm';
export type QuoteStatus = 'draft' | 'pending' | 'approved' | 'rejected' | 'delivered';
export type PendingProductStatus = 'pending' | 'approved' | 'rejected';
export type InvoiceStatus = 'draft' | 'open' | 'paid' | 'void' | 'uncollectible';
export type PaymentMethodType = 'card' | 'bank_account' | 'wallet' | 'qr_payment';
export type SubscriptionInterval = 'month' | 'quarter' | 'year';
export type ProductSource = 'approved' | 'pending' | 'custom';

