/**
 * Companies table entity
 * Multi-tenant company entities for the quotation system
 */
export interface Company {
  id: UUID;
  code: string;
  name: string;
  address: string | null;
  mobile: string | null;
  email: string | null;
  prepared_by: string | null;
  terms: string | null;
  del_note: string | null;
  closing_note: string | null;
  created_at: TimestampWithTimezone;
  updated_at: TimestampWithTimezone;
  cost_categories: string[]; // JSONB array
  currency: string;
  subscription_status: SubscriptionStatus;
  trial_end: TimestampWithTimezone | null;
}

/**
 * Users table entity
 * User accounts with company associations and authentication
 */
export interface User {
  id: UUID;
  company_id: UUID;
  email: string | null;
  password_hash: string | null;
  created_at: TimestampWithTimezone;
  name_encrypted: Bytea | null;
  email_encrypted: Bytea | null;
  email_hash: string | null;
  is_oauth_user: boolean | null;
  trial_expires_at: TimestampWithTimezone | null;
  subscription_activated: boolean | null;
  activation_code: string | null;
  discount_percent: number | null; // numeric
  subscription_plan: string | null;
  role: UserRole;
  is_admin: boolean | null;
}

