// ============================================================
// UTILITY TYPES FOR DATABASE OPERATIONS
// ============================================================

/**
 * Extract table name from entity type
 */
export type TableName<T> = T extends Company ? 'companies' :
  T extends User ? 'users' :
  T extends OAuthAccount ? 'oauth_accounts' :
  T extends PasswordResetToken ? 'password_reset_tokens' :
  T extends Product ? 'products' :
  T extends CompanyProduct ? 'company_products' :
  T extends CompanyCollection ? 'company_collections' :
  T extends CompanyProductDefinition ? 'company_product_definitions' :
  T extends PendingProduct ? 'pending_products' :
  T extends Quote ? 'quotes' :
  T extends QuoteItem ? 'quote_items' :
  T extends SubscriptionPlan ? 'subscription_plans' :
  T extends Subscription ? 'subscriptions' :
  T extends SubscriptionItem ? 'subscription_items' :
  T extends Invoice ? 'invoices' :
  T extends PaymentMethod ? 'payment_methods' :
  T extends WebhookEvent ? 'webhook_events' :
  T extends ActivationCode ? 'activation_codes' :
  never;

/**
 * Database entity type union
 */
export type DatabaseEntity =
  | Company
  | User
  | OAuthAccount
  | PasswordResetToken
  | Product
  | CompanyProduct
  | CompanyCollection
  | CompanyProductDefinition
  | PendingProduct
  | Quote
  | QuoteItem
  | SubscriptionPlan
  | Subscription
  | SubscriptionItem
  | Invoice
  | PaymentMethod
  | WebhookEvent
  | ActivationCode;